/*! normalize.css v3.0.1 | MIT License | git.io/normalize */html{font-family:sans-serif;-ms-text-size-adjust:100%;-webkit-text-size-adjust:100%}body{margin:0}article,aside,details,figcaption,figure,footer,header,hgroup,main,nav,section,summary{display:block}audio,canvas,progress,video{display:inline-block;vertical-align:baseline}audio:not([controls]){display:none;height:0}[hidden],template{display:none}a{background:transparent}a:active,a:hover{outline:0}abbr[title]{border-bottom:1px dotted}b,strong{font-weight:bold}dfn{font-style:italic}h1{font-size:2em;margin:.67em 0}mark{background:#ff0;color:#000}small{font-size:80%}sub,sup{font-size:75%;line-height:0;position:relative;vertical-align:baseline}sup{top:-0.5em}sub{bottom:-0.25em}img{border:0}svg:not(:root){overflow:hidden}figure{margin:1em 40px}hr{-moz-box-sizing:content-box;box-sizing:content-box;height:0}pre{overflow:auto}code,kbd,pre,samp{font-family:monospace,monospace;font-size:1em}button,input,optgroup,select,textarea{color:inherit;font:inherit;margin:0}button{overflow:visible}button,select{text-transform:none}button,html input[type="button"],input[type="reset"],input[type="submit"]{-webkit-appearance:button;cursor:pointer}button[disabled],html input[disabled]{cursor:default}button::-moz-focus-inner,input::-moz-focus-inner{border:0;padding:0}input{line-height:normal}input[type="checkbox"],input[type="radio"]{box-sizing:border-box;padding:0}input[type="number"]::-webkit-inner-spin-button,input[type="number"]::-webkit-outer-spin-button{height:auto}input[type="search"]{-webkit-appearance:textfield;-moz-box-sizing:content-box;-webkit-box-sizing:content-box;box-sizing:content-box}input[type="search"]::-webkit-search-cancel-button,input[type="search"]::-webkit-search-decoration{-webkit-appearance:none}fieldset{border:1px solid #c0c0c0;margin:0 2px;padding:.35em .625em .75em}legend{border:0;padding:0}textarea{overflow:auto}optgroup{font-weight:bold}table{border-collapse:collapse;border-spacing:0}td,th{padding:0}
/*
<!-- Constants -->

<Variable name="damionRegular36" description="Damion Regular 36" type="font" default="400 36px 'Noto Naskh Arabic', serif" hideEditor="true" value="400 36px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="damionRegular62" description="Damion Regular 62" type="font" default="400 62px 'Noto Naskh Arabic', serif" hideEditor="true" value="400 62px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="playfairDisplayBlack28" description="Playfair Display Black 28" type="font" default="700 28px 'Noto Naskh Arabic', serif" hideEditor="true" value="700 28px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="playfairDisplayBlack36" description="Playfair Display Black 36" type="font" default="700 36px 'Noto Naskh Arabic', serif" hideEditor="true" value="700 36px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="playfairDisplayBlack44" description="Playfair Display Black 44" type="font" default="700 44px 'Noto Naskh Arabic', serif" hideEditor="true" value="700 44px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="robotoNormal15" description="Roboto Normal 15" type="font" default="16px 'Noto Naskh Arabic', serif" hideEditor="true" value="16px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="robotoNormal16" description="Roboto Normal 16" type="font" default="17px 'Noto Naskh Arabic', serif" hideEditor="true" value="17px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="robotoLightItalic15" description="Roboto Light Italic 15" type="font" default="400 16px 'Noto Naskh Arabic', serif" hideEditor="true" value="400 16px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="robotoBold22" description="Roboto Bold 22" type="font" default="700 22px 'Noto Naskh Arabic', serif" hideEditor="true" value="700 22px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="robotoBold30" description="Roboto Bold 30" type="font" default="700 30px 'Noto Naskh Arabic', serif" hideEditor="true" value="700 30px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="robotoBold45" description="Roboto Bold 45" type="font" default="700 42px 'Noto Naskh Arabic', serif" hideEditor="true" value="700 42px &#39;Noto Naskh Arabic&#39;, serif"/>

<!-- Variable definitions -->

<Variable name="keycolor" description="Main Color" type="color" default="#9b59b6" value="#9b59b6"/>
<Variable name="startSide" description="Start side in blog language" type="automatic" default="left" hideEditor="true" />
<Variable name="endSide" description="End side in blog language" type="automatic" default="right" hideEditor="true" />

<Group description="Page Text">
<Variable name="body.text.font" description="Font" type="font" default="$(robotoNormal15)" value="16px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="body.text.color" description="Color" type="color" default="#c8c8d0" value="#c8c8d0"/>
</Group>

<Group description="Backgrounds">
<Variable name="body.background.height" description="Background height" type="length" min="420px" max="640px" default="480px" value="480px"/>
<Variable name="body.background" description="Background" color="$(body.background.color)" type="background" default="$(color) none repeat scroll top left" value="$(color) none repeat scroll top left"/>
<Variable name="body.background.color" description="Body background color" type="color" default="#0d0d14" value="#0d0d14"/>
<Variable name="posts.background.color" description="Post background color" type="color" default="#1a1a2e" value="#1a1a2e"/>
<Variable name="body.background.blur" description="Background blur" type="length" min="0px" max="50px" default="0px" value="0px"/>
</Group>

<Group description="Links">
<Variable name="body.link.color" description="Link color" type="color" default="#bb86fc" value="#bb86fc"/>
<Variable name="body.link.visited.color" description="Visited link color" type="color" default="$(body.link.color)" value="#bb86fc"/>
<Variable name="body.link.hover.color" description="Link Hover Color" type="color" default="$(body.link.color)" value="#d4a8ff"/>
</Group>

<Group description="Blog title" selector="div.widget.Header">
<Variable name="blog.title.font" description="Font" type="font" default="$(robotoBold45)" value="700 42px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="blog.title.color" description="Color" type="color" default="#fff" value="#ffffff"/>
<Variable name="header.icons.color" description="Background icons color" type="color" default="#fff" value="#ffffff"/>
</Group>

<Group description="Tabs text" selector="div.widget.PageList">
<Variable name="tabs.font" description="Font" type="font" family="$(robotoNormal15.family)" size="$(robotoNormal15.size)" default="700 normal $(size) $(family)" value="700 normal $(size) $(family)"/>
<Variable name="tabs.color" description="Text color" type="color" default="#8a8a9a" value="#8a8a9a"/>
<Variable name="tabs.selected.color" description="Selected color" type="color" default="#f4d03f" value="#f4d03f"/>
<Variable name="tabs.overflow.background.color" description="Popup background color" type="color" default="$(posts.background.color)" value="#1a1a2e"/>
<Variable name="tabs.overflow.color" description="Popup text color" type="color" default="$(posts.text.color)" value="#c8c8d0"/>
<Variable name="tabs.overflow.selected.color" description="Popup selected color" type="color" default="$(posts.title.color)" value="#f5f5f5"/>
</Group>

<Group description="Posts" selector="div.widget.Blog">
<Variable name="posts.title.color" description="Post title color" type="color" default="#f5f5f5" value="#f5f5f5"/>
<Variable name="posts.title.font" description="Post title font" type="font" default="$(robotoBold22)" value="700 22px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="posts.stream.title.font" description="Post title stream font" type="font" default="$(robotoBold30)" value="700 30px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="posts.text.font" description="Post text font" type="font" default="$(body.text.font)" value="16px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="posts.text.color" description="Post text color" type="color" default="$(body.text.color)" value="#c8c8d0"/>
<Variable name="posts.byline.color" description="Post byline color" type="color" default="rgba(255, 255, 255, 0.5)" value="rgba(255, 255, 255, 0.5)"/>
<Variable name="blockquote.font" description="Blockquote font" type="font" default="$(robotoLightItalic15)" value="400 16px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="blockquote.color" description="Blockquote color" type="color" default="#b0b0c0" value="#b0b0c0"/>
<Variable name="posts.icons.color" description="Post icons color" type="color" default="#8a8a9a" value="#8a8a9a"/>
</Group>

<Group description="Search">
<Variable name="search.input.color" description="Input color" type="color" default="$(blog.title.color)" value="#ffffff"/>
<Variable name="search.input.font" description="Input font" type="font" default="$(robotoNormal16)" value="17px &#39;Noto Naskh Arabic&#39;, serif"/>
<Variable name="search.placeholder.color" description="Placeholder text color" type="color" default="$(blog.title.color)" value="#ffffff"/>
</Group>

<Group description="Sharing">
<Variable name="sharing.background.color" description="Sharing background color" type="color" default="$(posts.background.color)" value="#1a1a2e"/>
<Variable name="sharing.text.color" description="Sharing text color" type="color" default="$(posts.title.color)" value="#f5f5f5"/>
<Variable name="sharing.icons.color" description="Sharing icons color" type="color" default="$(sharing.text.color)" value="#f5f5f5"/>
</Group>

<Group description="Popular posts" selector="div.widget.PopularPosts">
<Variable name="popularposts.background.color" description="Popular post background color" type="color" default="$(body.background.color)" value="#141428"/>
<Variable name="popularposts.byline.color" description="Popular post byline color" type="color" default="$(posts.byline.color)" value="rgba(255, 255, 255, 0.5)"/>
<Variable name="popularposts.title.color" description="Popular post title color" type="color" default="$(posts.title.color)" value="#f5f5f5"/>
<Variable name="popularposts.text.color" description="Popular post text color" type="color" default="$(posts.text.color)" value="#c8c8d0"/>
<Variable name="popularposts.link.color" description="Popular post link color" type="color" default="$(body.link.color)" value="#bb86fc"/>
</Group>

<Group description="Post navigation" selector='div.blog-pager'>
<Variable name="posts.navigation.link.color" description="Post navigation links color" type="color" default="$(body.link.color)" value="#bb86fc"/>
<Variable name="posts.navigation.link.visited.color" description="Post navigation links visited color" type="color" default="$(body.link.visited.color)" value="#bb86fc"/>
<Variable name="posts.navigation.link.hover.color" description="Post navigations links hover color" type="color" default="$(body.link.hover.color)" value="#d4a8ff"/>
</Group>

<Group description="Sidebar" selector="div.sidebar-container">
<Variable name="sidebar.backgroundColorTop" description="Background color (Top)" type="color" default="#16162a" value="#16162a"/>
<Variable name="sidebar.backgroundColorTopHD" description="Background color (Top) - HD" type="color" default="rgba(22, 22, 42, 1)" value="#16162a"/>
<Variable name="sidebar.backgroundColorBottom" description="Background color (Bottom)" type="color" default="#16162a" value="#16162a"/>
<Variable name="sidebar.separator.color" description="Separator color" type="color" default="#2d2d4a" value="#2d2d4a"/>
<Variable name="widget.title.color" description="Gadget title color" type="color" default="#f5f5f5" value="#f5f5f5"/>
<Variable name="sidebar.icons.color" description="Sidebar icons color" type="color" default="#8a8a9a" value="#8a8a9a"/>
</Group>

<Group description="Author profile" selector='.widget.Profile'>
<Variable name="profile.title.color" description="Profile title color" type="color" default="rgba(255,255,255,0.52)" value="rgba(255,255,255,0.52)"/>
<Variable name="profile.text.color" description="Profile text color" type="color" default="rgba(255, 255, 255, 0.5)" value="rgba(255, 255, 255, 0.5)"/>
<Variable name="profile.link.color" description="Profile link color" type="color" default="$(posts.title.color)" value="#f5f5f5"/>
</Group>

<Group description="Labels" selector=".widget.Label">
<Variable name="labels.text.color" description="Label text color" type="color" default="$(body.link.color)" value="#bb86fc"/>
<Variable name="labels.background.color" description="Label background color" type="color" red="$(labels.text.color.red)" green="$(labels.text.color.green)" blue="$(labels.text.color.blue)" default="rgba($red, $green, $blue, 0.08)" value="rgba(155,89,182,0.08)"/>
</Group>

<Group description="Attribution" selector=".widget.Attribution">
<Variable name="attribution.text.color" description="Attribution text color" type="color" default="$(body.text.color)" value="#8a8a9a"/>
<Variable name="attribution.link.color" description="Attribution link color" type="color" default="$(body.link.color)" value="#f4d03f"/>
<Variable name="attribution.icon.color" description="Attribution icon color" type="color" default="#8a8a9a" hideEditor="true" value="#f4d03f"/>
</Group>

<Group description="Widths">
<Variable name="sidebar.width" description="Sidebar width" type="length" min="100px" max="1000px" default="284px" value="284px"/>
<Variable name="content.width" description="Content width" type="length" min="600px" max="2400px" default="922px" value="922px"/>
<Variable name="content.margin" description="Content margin" type="length" min="0px" max="1000px" default="117px" value="117px"/>
</Group>
 */

/*!************************************************
 * Blogger Template Style
 * Name: Contempo
 **************************************************/
body{
overflow-wrap:break-word;
word-break:break-word;
word-wrap:break-word
}
.hidden{
display:none
}
.invisible{
visibility:hidden
}
.container::after,.float-container::after{
clear:both;
content:"";
display:table
}
.clearboth{
clear:both
}
#comments .comment .comment-actions,.subscribe-popup .FollowByEmail .follow-by-email-submit,.widget.Profile .profile-link,.widget.Profile .profile-link.visit-profile{
background:0 0;
border:0;
box-shadow:none;
color:$(body.link.color);
cursor:pointer;
font-size:14px;
font-weight:700;
outline:0;
text-decoration:none;
text-transform:uppercase;
width:auto
}
.dim-overlay{
background-color:rgba(0,0,0,.54);
height:100vh;
left:0;
position:fixed;
top:0;
width:100%
}
#sharing-dim-overlay{
background-color:transparent
}
input::-ms-clear{
display:none
}
.blogger-logo,.svg-icon-24.blogger-logo{
fill:#ff9800;
opacity:1
}
.loading-spinner-large{
-webkit-animation:mspin-rotate 1.568s infinite linear;
animation:mspin-rotate 1.568s infinite linear;
height:48px;
overflow:hidden;
position:absolute;
width:48px;
z-index:200
}
.loading-spinner-large>div{
-webkit-animation:mspin-revrot 5332ms infinite steps(4);
animation:mspin-revrot 5332ms infinite steps(4)
}
.loading-spinner-large>div>div{
-webkit-animation:mspin-singlecolor-large-film 1333ms infinite steps(81);
animation:mspin-singlecolor-large-film 1333ms infinite steps(81);
background-size:100%;
height:48px;
width:3888px
}
.mspin-black-large>div>div,.mspin-grey_54-large>div>div{
background-image:url(https://www.blogblog.com/indie/mspin_black_large.svg)
}
.mspin-white-large>div>div{
background-image:url(https://www.blogblog.com/indie/mspin_white_large.svg)
}
.mspin-grey_54-large{
opacity:.54
}
@-webkit-keyframes mspin-singlecolor-large-film{
from{
-webkit-transform:translateX(0);
transform:translateX(0)
}
to{
-webkit-transform:translateX(-3888px);
transform:translateX(-3888px)
}
}
@keyframes mspin-singlecolor-large-film{
from{
-webkit-transform:translateX(0);
transform:translateX(0)
}
to{
-webkit-transform:translateX(-3888px);
transform:translateX(-3888px)
}
}
@-webkit-keyframes mspin-rotate{
from{
-webkit-transform:rotate(0);
transform:rotate(0)
}
to{
-webkit-transform:rotate(360deg);
transform:rotate(360deg)
}
}
@keyframes mspin-rotate{
from{
-webkit-transform:rotate(0);
transform:rotate(0)
}
to{
-webkit-transform:rotate(360deg);
transform:rotate(360deg)
}
}
@-webkit-keyframes mspin-revrot{
from{
-webkit-transform:rotate(0);
transform:rotate(0)
}
to{
-webkit-transform:rotate(-360deg);
transform:rotate(-360deg)
}
}
@keyframes mspin-revrot{
from{
-webkit-transform:rotate(0);
transform:rotate(0)
}
to{
-webkit-transform:rotate(-360deg);
transform:rotate(-360deg)
}
}
.skip-navigation{
background-color:#fff;
box-sizing:border-box;
color:#000;
display:block;
height:0;
left:0;
line-height:50px;
overflow:hidden;
padding-top:0;
position:fixed;
text-align:center;
top:0;
-webkit-transition:box-shadow .3s,height .3s,padding-top .3s;
transition:box-shadow .3s,height .3s,padding-top .3s;
width:100%;
z-index:900
}
.skip-navigation:focus{
box-shadow:0 4px 5px 0 rgba(0,0,0,.14),0 1px 10px 0 rgba(0,0,0,.12),0 2px 4px -1px rgba(0,0,0,.2);
height:50px
}
#main{
outline:0
}
.main-heading{
position:absolute;
clip:rect(1px,1px,1px,1px);
padding:0;
border:0;
height:1px;
width:1px;
overflow:hidden
}
.Attribution{
margin-top:1em;
text-align:center
}
.Attribution .blogger img,.Attribution .blogger svg{
vertical-align:bottom
}
.Attribution .blogger img{
margin-$endSide:.5em
}
.Attribution div{
line-height:24px;
margin-top:.5em
}
.Attribution .copyright,.Attribution .image-attribution{
font-size:.7em;
margin-top:1.5em
}
.BLOG_mobile_video_class{
display:none
}
.bg-photo{
background-attachment:scroll!important
}
body .CSS_LIGHTBOX{
z-index:900
}
.extendable .show-less,.extendable .show-more{
border-color:$(body.link.color);
color:$(body.link.color);
margin-top:8px
}
.extendable .show-less.hidden,.extendable .show-more.hidden{
display:none
}
.inline-ad{
display:none;
max-width:100%;
overflow:hidden
}
.adsbygoogle{
display:block
}
#cookieChoiceInfo{
bottom:0;
top:auto
}
iframe.b-hbp-video{
border:0
}
.post-body img{
max-width:100%
}
.post-body iframe{
max-width:100%
}
.post-body a[imageanchor="1"]{
display:inline-block
}
.byline{
margin-$endSide:1em
}
.byline:last-child{
margin-$endSide:0
}
.link-copied-dialog{
max-width:520px;
outline:0
}
.link-copied-dialog .modal-dialog-buttons{
margin-top:8px
}
.link-copied-dialog .goog-buttonset-default{
background:0 0;
border:0
}
.link-copied-dialog .goog-buttonset-default:focus{
outline:0
}
.paging-control-container{
margin-bottom:16px
}
.paging-control-container .paging-control{
display:inline-block
}
.paging-control-container .comment-range-text::after,.paging-control-container .paging-control{
color:$(body.link.color)
}
.paging-control-container .comment-range-text,.paging-control-container .paging-control{
margin-$endSide:8px
}
.paging-control-container .comment-range-text::after,.paging-control-container .paging-control::after{
content:"\b7";
cursor:default;
padding-$startSide:8px;
pointer-events:none
}
.paging-control-container .comment-range-text:last-child::after,.paging-control-container .paging-control:last-child::after{
content:none
}
.byline.reactions iframe{
height:20px
}
.b-notification{
color:#000;
background-color:#fff;
border-bottom:solid 1px #000;
box-sizing:border-box;
padding:16px 32px;
text-align:center
}
.b-notification.visible{
-webkit-transition:margin-top .3s cubic-bezier(.4,0,.2,1);
transition:margin-top .3s cubic-bezier(.4,0,.2,1)
}
.b-notification.invisible{
position:absolute
}
.b-notification-close{
position:absolute;
right:8px;
top:8px
}
.no-posts-message{
line-height:40px;
text-align:center
}
@media screen and (max-width:800px){
body.item-view .post-body a[imageanchor="1"][style*="float: left;"],body.item-view .post-body a[imageanchor="1"][style*="float: right;"]{
float:none!important;
clear:none!important
}
body.item-view .post-body a[imageanchor="1"] img{
display:block;
height:auto;
margin:0 auto
}
body.item-view .post-body>.separator:first-child>a[imageanchor="1"]:first-child{
margin-top:20px
}
.post-body a[imageanchor]{
display:block
}
body.item-view .post-body a[imageanchor="1"]{
margin-left:0!important;
margin-right:0!important
}
body.item-view .post-body a[imageanchor="1"]+a[imageanchor="1"]{
margin-top:16px
}
}
.item-control{
display:none
}
#comments{
border-top:1px dashed rgba(0,0,0,.54);
margin-top:20px;
padding:20px
}
#comments .comment-thread ol{
margin:0;
padding-left:0;
padding-$startSide:0
}
#comments .comment .comment-replybox-single,#comments .comment-thread .comment-replies{
margin-left:60px
}
#comments .comment-thread .thread-count{
display:none
}
#comments .comment{
list-style-type:none;
padding:0 0 30px;
position:relative
}
#comments .comment .comment{
padding-bottom:8px
}
.comment .avatar-image-container{
position:absolute
}
.comment .avatar-image-container img{
border-radius:50%
}
.avatar-image-container svg,.comment .avatar-image-container .avatar-icon{
border-radius:50%;
border:solid 1px $(posts.icons.color);
box-sizing:border-box;
fill:$(posts.icons.color);
height:35px;
margin:0;
padding:7px;
width:35px
}
.comment .comment-block{
margin-top:10px;
margin-$startSide:60px;
padding-bottom:0
}
#comments .comment-author-header-wrapper{
margin-left:40px
}
#comments .comment .thread-expanded .comment-block{
padding-bottom:20px
}
#comments .comment .comment-header .user,#comments .comment .comment-header .user a{
color:$(posts.title.color);
font-style:normal;
font-weight:700
}
#comments .comment .comment-actions{
margin-top:10px;
position:relative;
display:flex;
gap:10px;
}
#comments .comment .comment-header .datetime{
bottom:0;
color:rgba($(posts.title.color.red),$(posts.title.color.green),$(posts.title.color.blue),.54);
display:inline-block;
font-size:13px;
font-style:italic;
margin-$startSide:8px
}
#comments .comment .comment-footer .comment-timestamp a,#comments .comment .comment-header .datetime a{
color:rgba($(posts.title.color.red),$(posts.title.color.green),$(posts.title.color.blue),.54)
}
#comments .comment .comment-content,.comment .comment-body{
margin-top:12px;
word-break:break-word
}
.comment-body{
margin-bottom:12px
}
#comments.embed[data-num-comments="0"]{
border:0;
margin-top:0;
padding-top:0
}
#comments.embed[data-num-comments="0"] #comment-post-message,#comments.embed[data-num-comments="0"] div.comment-form>p{
display:none
}
#comments.embed[data-num-comments="0"] p.comment-footer{
display:block !important
}
#comment-editor-src{
display:none
}
.comments .comments-content .loadmore.loaded{
max-height:0;
opacity:0;
overflow:hidden
}
.extendable .remaining-items{
height:0;
overflow:hidden;
-webkit-transition:height .3s cubic-bezier(.4,0,.2,1);
transition:height .3s cubic-bezier(.4,0,.2,1)
}
.extendable .remaining-items.expanded{
height:auto
}
.svg-icon-24,.svg-icon-24-button{
cursor:pointer;
height:24px;
width:24px;
min-width:24px
