margin-left:40px
}
}

head.b:template-skin:

body#layout .hidden,
body#layout .invisible {
  display: inherit;
}
body#layout .navigation {
  display: none;
}
body#layout .page,
body#layout .sidebar_top,
body#layout .sidebar_bottom {
  display: inline-block;
  left: inherit;
  position: relative;
  vertical-align: top;
}
body#layout .page {
  float: right;
  margin-left: 20px;
  width: 55%;
}
body#layout .sidebar-container {
  float: right;
  width: 40%;
}
body#layout .arwn-hamburger-menu {
  display: none;
}

body.script:
//                                    
(function() {
  // Apply saved theme immediately to prevent flash
  var savedTheme = localStorage.getItem('arwn-theme') || 'dark';
  document.documentElement.setAttribute('data-theme', savedTheme);

  // Wait for DOM to be ready
  document.addEventListener('DOMContentLoaded', function() {
    var toggleBtn = document.getElementById('themeToggle');
    var themeIcon = document.getElementById('themeIcon');

    if (!toggleBtn || !themeIcon) return;

    // Set initial icon
    var currentTheme = document.documentElement.getAttribute('data-theme') || 'dark';
    themeIcon.textContent = currentTheme === 'dark' ? '☀️' : '🌙';

    // Toggle handler
    toggleBtn.addEventListener('click', function() {
      var current = document.documentElement.getAttribute('data-theme') || 'dark';
      var newTheme = current === 'dark' ? 'light' : 'dark';

      document.documentElement.setAttribute('data-theme', newTheme);
      localStorage.setItem('arwn-theme', newTheme);
      themeIcon.textContent = newTheme === 'dark' ? '☀️' : '🌙';

      // Add a small animation to the button
      toggleBtn.style.transform = 'scale(1.2) rotate(180deg)';
      setTimeout(function() {
        toggleBtn.style.transform = '';
      }, 300);
    });

              // Mobile sidebar fallback for custom header layout.
    var sidebar = document.querySelector('.sidebar-container');
    var menuButtons = document.querySelectorAll('.arwn-hamburger-menu');
    var closeButtons = document.querySelectorAll('.sidebar-back');

    function openSidebar(event) {
      if (!sidebar) return;
      if (event) {
        event.preventDefault();
        event.stopPropagation();
      }
      sidebar.classList.remove('sidebar-invisible');
      document.body.classList.add('sidebar-visible');
    }

    function closeSidebar(event) {
      if (!sidebar) return;
      if (event) {
        event.preventDefault();
        event.stopPropagation();
      }
      sidebar.classList.add('sidebar-invisible');
      document.body.classList.remove('sidebar-visible');
    }

    if (menuButtons) {
      menuButtons.forEach(function(button) {
        button.addEventListener('click', openSidebar, true);
        button.addEventListener('touchstart', openSidebar, {passive: false, capture: true});
      });
    }

    if (closeButtons) {
      closeButtons.forEach(function(button) {
        button.addEventListener('click', closeSidebar, true);
        button.addEventListener('touchstart', closeSidebar, {passive: false, capture: true});
      });
    }

    document.addEventListener('click', function(event) {
      if (!document.body.classList.contains('sidebar-visible') || !sidebar) return;
      if (sidebar.contains(event.target)) return;

      var isMenuBtn = false;
      menuButtons.forEach(function(btn) { if (btn.contains(event.target)) isMenuBtn = true; });
      if (isMenuBtn) return;

      closeSidebar(event);
    }, true);
    document.addEventListener('keydown', function(event) {
      if (event.key === 'Escape') closeSidebar();
    });

    // =============================================
    // PREMIUM HEADER SEARCH OVERLAY CONTROLLERS
    // =============================================
    var searchContainer = document.querySelector('.search');
    var searchExpandBtn = document.querySelector('.search-expand');
    var searchCloseBtn = document.querySelector('.search-close-btn');
    var searchInput = document.querySelector('.search-input input');
    var searchDimOverlay = document.querySelector('.search-dim-overlay');

    function openSearch(e) {
      if (!searchContainer) return;
      if (e) {
        e.preventDefault();
        e.stopPropagation();
      }
      searchContainer.classList.add('focused');
      document.body.classList.add('search-visible');

      // Auto-focus after the slide transition completes
      setTimeout(function() {
        if (searchInput) {
          searchInput.focus();
          searchInput.select();
        }
      }, 100);
    }

    function closeSearch(e) {
      if (!searchContainer) return;
      if (e) {
        e.preventDefault();
        e.stopPropagation();
      }
      searchContainer.classList.remove('focused');
      document.body.classList.remove('search-visible');
    }

    if (searchExpandBtn) {
      searchExpandBtn.addEventListener('click', openSearch, true);
      searchExpandBtn.addEventListener('touchstart', openSearch, {passive: false, capture: true});
    }

    if (searchCloseBtn) {
      searchCloseBtn.addEventListener('click', closeSearch, true);
      searchCloseBtn.addEventListener('touchstart', closeSearch, {passive: false, capture: true});
    }

    if (searchDimOverlay) {
      searchDimOverlay.addEventListener('click', closeSearch, true);
      searchDimOverlay.addEventListener('touchstart', closeSearch, {passive: false, capture: true});
    }

    // Close search on Escape key press
    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && searchContainer && searchContainer.classList.contains('focused')) {
        closeSearch();
      }
    });

    function resizeCommentEditor() {
      var iframe = document.getElementById('comment-editor');
      if (!iframe) return;
      var minHeight = 400;
      if (window.matchMedia('(max-width: 380px)').matches) {
        minHeight = 280;
      } else if (window.matchMedia('(max-width: 600px)').matches) {
        minHeight = 300;
      } else if (window.matchMedia('(max-width: 768px)').matches) {
        minHeight = 340;
      }
      var attrHeight = parseInt(iframe.getAttribute('height'), 10);
      var nextHeight = Math.max(minHeight, attrHeight || minHeight);
      iframe.style.height = nextHeight + 'px';
    }

    function watchCommentEditorHeight() {
      var iframe = document.getElementById('comment-editor');
      if (!iframe || iframe.dataset.arwnHeightWatch === '1') return;
      iframe.dataset.arwnHeightWatch = '1';
      var observer = new MutationObserver(function() {
        resizeCommentEditor();
      });
      observer.observe(iframe, { attributes: true, attributeFilter: ['height', 'style'] });
      resizeCommentEditor();
    }

    function isAllowedCommentFrameSrc(src) {
      if (!src || src === 'about:blank') return true;
      var lower = String(src).toLowerCase();
      if (/google|gstatic|googleusercontent|blogger\.com/.test(lower)) return true;
      try {
        var parsed = new URL(src, window.location.href);
        var host = parsed.hostname.replace(/^www\./, '');
        var pageHost = window.location.hostname.replace(/^www\./, '');
        var pathQuery = (parsed.pathname + parsed.search).toLowerCase();
        if (host === pageHost) {
          return /comment|gadget|rpc|embed|postcomment|form/.test(pathQuery);
        }
        if (/\.blogspot\./.test(host) && /comment|gadget|rpc|embed|postcomment|form/.test(pathQuery)) {
          return true;
        }
      } catch (e) {
        return false;
      }
      return true;
    }

    function blockCommentFrame(frame) {
      if (!frame || frame.id === 'comment-actions') return;
      frame.setAttribute('src', 'about:blank');
      frame.classList.add('arwn-blocked-frame');
      var replyBox = frame.closest('.comment-replybox-single');
      if (replyBox) {
        replyBox.classList.remove('arwn-reply-active');
        replyBox.classList.add('arwn-blocked-reply');
      }
    }

    function guardCommentIframes() {
      document.querySelectorAll('#comments iframe').forEach(function(frame) {
        if (frame.id === 'comment-actions') return;
        var src = frame.getAttribute('src') || '';
        if (!isAllowedCommentFrameSrc(src)) {
          blockCommentFrame(frame);
          return;
        }
        if (frame.dataset.arwnGuardBound === '1') return;
        frame.dataset.arwnGuardBound = '1';
        frame.addEventListener('load', function() {
          var current = frame.getAttribute('src') || '';
          if (!isAllowedCommentFrameSrc(current)) blockCommentFrame(frame);
        });
      });
    }

    function prepareReplyBoxes() {
      document.querySelectorAll('#comments .comment-replybox-single').forEach(function(box) {
        if (box.classList.contains('arwn-blocked-reply')) return;
        // Only block/resize iframes, don't toggle visibility here to prevent flashing
        var frame = box.querySelector('iframe');
        if (frame) {
          var src = frame.getAttribute('src') || '';
          if (!isAllowedCommentFrameSrc(src)) blockCommentFrame(frame);
        }
      });
    }

    function removeNestedBlogLayout() {
      var holder = document.getElementById('comment-holder');
      if (!holder) return;
      // Be careful not to remove the REAL elements if they get caught in a broad selector
      holder.querySelectorAll(
        '#comment-holder .page_body, #comment-holder .centered-top-container, #comment-holder .arwn-flex-header, #comment-holder .blog-posts, #comment-holder #footer, #comment-holder .sidebar-container'
      ).forEach(function(node) {
        node.parentNode.removeChild(node);
      });
      // Also remove any empty paragraphs or stray breaks at the bottom
      holder.querySelectorAll('p:empty, br').forEach(function(node) {
        if (!node.nextSibling && node.parentNode === holder) node.parentNode.removeChild(node);
      });
    }

    function cleanupCommentsJunk() {
      removeNestedBlogLayout();

      // Comprehensive deleted comment detection
      document.querySelectorAll('#comments .comment.deleted, #comments .comment-body.deleted').forEach(function(el) {
        var comment = el.closest('.comment') || el.closest('.comment-thread') || (el.classList.contains('comment') ? el : null);
        if (comment && !comment.dataset.arwnHiding) {
          comment.dataset.arwnHiding = '1';
          var replies = comment.querySelector('.comment-replies');
          if (!replies || !replies.textContent.trim()) {
            comment.style.display = 'none';
            comment.classList.add('arwn-deleted-comment');
          } else {
            // Hide only the deleted part but keep the thread structure
            if (el.classList.contains('comment')) {
               var b = el.querySelector('.comment-body, .comment-content');
               if (b) b.style.display = 'none';
               var h = el.querySelector('.comment-header, .comment-author');
               if (h) h.style.display = 'none';
            } else {
               el.style.display = 'none';
            }
          }
        }
      });

      document.querySelectorAll('#comments h4.arwn-comment-form-label').forEach(function(node) {
        // Only hide the label if the iframe is no longer immediately after it in the original container
        var wrapper = node.nextElementSibling;
        if (wrapper && wrapper.classList.contains('comment-form')) {
           var iframe = wrapper.querySelector('iframe');
           if (!iframe) node.style.display = 'none';
        } else if (wrapper && wrapper.classList.contains('arwn-comment-editor-wrap')) {
           var iframe = wrapper.querySelector('iframe');
           if (!iframe) node.style.display = 'none';
        } else if (!document.querySelector('.comment-footer iframe')) {
           node.style.display = 'none';
        }
      });

      var titles = document.querySelectorAll('#comments #comment-post-message');
      for (var t = 1; t < titles.length; t++) {
        titles[t].parentNode.removeChild(titles[t]);
      }

      document.querySelectorAll('#comments .comment-actions').forEach(function(actions) {
        actions.querySelectorAll('a').forEach(function(link) {
          var txt = (link.textContent || '').trim();
          if (!txt && !link.querySelector('img') && !link.querySelector('svg')) {
            link.parentNode.removeChild(link);
          }
        });
        if (!actions.children.length) actions.style.display = 'none';
      });

      // Cleanup extra whitespace at bottom of panel
      var panel = document.querySelector('.arwn-comments-panel');
      if (panel) {
        var lastChild = panel.lastElementChild;
        while (lastChild && (lastChild.tagName === 'BR' || lastChild.tagName === 'HR' || (lastChild.tagName === 'P' && !lastChild.textContent.trim()) || lastChild.classList.contains('clear'))) {
          var prev = lastChild.previousElementSibling;
          panel.removeChild(lastChild);
          lastChild = prev;
        }
      }

      // Remove unwanted Blogger elements inside comment-holder
      var holder = document.getElementById('comment-holder');
      if (holder) {
        holder.querySelectorAll('.comment-thread-inline-ad, .thread-count, .loadmore-loading, .thread-separator').forEach(function(el) {
          el.style.display = 'none';
        });
      }

      prepareReplyBoxes();
      guardCommentIframes();
      resizeCommentEditor();
    }

    function watchCommentHolder() {
      var holder = document.getElementById('comment-holder');
      if (!holder || holder.dataset.arwnWatchBound === '1') return;
      holder.dataset.arwnWatchBound = '1';
      var observer = new MutationObserver(function() {
        cleanupCommentsJunk();
      });
      observer.observe(holder, { childList: true, subtree: true });
      cleanupCommentsJunk();
    }

    function initCommentsPanel() {
      var commentsBox = document.querySelector('.arwn-comments-box');
      if (!commentsBox) return;

      function onCommentsToggle() {
        watchCommentHolder();
        cleanupCommentsJunk();
        watchCommentEditorHeight();
        resizeCommentEditor();
        window.setTimeout(function() {
          cleanupCommentsJunk();
          resizeCommentEditor();
        }, 250);
        window.setTimeout(function() {
          cleanupCommentsJunk();
          resizeCommentEditor();
        }, 900);
        window.setTimeout(function() {
          cleanupCommentsJunk();
          resizeCommentEditor();
        }, 1800);
      }

      commentsBox.addEventListener('toggle', onCommentsToggle);
      watchCommentHolder();
      cleanupCommentsJunk();
      if (commentsBox.open) onCommentsToggle();
      window.addEventListener('resize', function() {
        if (commentsBox.open) resizeCommentEditor();
      });
      document.addEventListener('click', function(event) {
        var reply = event.target.closest('.comment-reply, .comment-reply-link');
        if (!reply) return;

        // If it's Blogger's default threaded reply, we might need to help it
        var comment = reply.closest('.comment') || reply.closest('.comment-thread');
        if (comment) {
          var replyBox = comment.querySelector('.comment-replybox-single');
          if (replyBox) {
            event.preventDefault();
            // Reset others
            document.querySelectorAll('.comment-replybox-single.arwn-reply-active').forEach(function(b) {
              if (b !== replyBox) b.classList.remove('arwn-reply-active');
            });
            replyBox.classList.add('arwn-reply-active');

            // Ensure iframe is loaded/resized
            var iframe = replyBox.querySelector('iframe');
            if (iframe && !iframe.src) {
              var srcLink = document.getElementById('comment-editor-src');
              if (srcLink) {
                var baseSrc = srcLink.href;
                var commentId = (comment.id || '').replace('c', '');
                if (commentId) iframe.src = baseSrc + '&parentID=' + commentId;
              }
            }
          }
        }
        window.setTimeout(cleanupCommentsJunk, 400);
      });
    }

    function openCommentsIfLinked() {
      if (!/^#(?:comments|comment-form|c\d+)/.test(window.location.hash || '')) return;
      var commentsBox = document.querySelector('.arwn-comments-box');
      if (commentsBox) {
        commentsBox.open = true;
        resizeCommentEditor();
      }
    }

    initCommentsPanel();
    openCommentsIfLinked();
    window.addEventListener('hashchange', openCommentsIfLinked);
  });
})();
//

//                              
(function() {
  document.addEventListener('DOMContentLoaded', function() {

    // === Utility: Get post labels from page ===
    function getPostLabels() {
      var labels = [];
      var labelEls = document.querySelectorAll('.byline.post-labels a');
      labelEls.forEach(function(el) {
        labels.push(el.textContent.trim());
      });
      return labels;
    }

    // === Utility: Find novel label (starts with رواية-) ===
    function getNovelLabel(labels) {
      for (var i = 0; i < labels.length; i++) {
        if (labels[i].indexOf('رواية-') === 0) return labels[i];
      }
      return null;
    }

    // === Utility: Check if current page is a single post ===
    function isSinglePost() {
      return document.body.classList.contains('item-view');
    }

    // === Utility: Format date in Arabic ===
    function formatDate(dateStr) {
      var d = new Date(dateStr);
      var months = ['يناير','فبراير','مارس','أبريل','مايو','يونيو',
                    'يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];
      return d.getDate() + ' ' + months[d.getMonth()] + ' ' + d.getFullYear();
    }

    // === Fetch all entries for a label (handles pagination) ===
    function fetchAllByLabel(label, callback) {
      var allEntries = [];
      var baseUrl = '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json&max-results=150';

      function fetchPage(startIndex) {
        var url = baseUrl + '&start-index=' + startIndex;
        var xhr = new XMLHttpRequest();
        xhr.open('GET', url, true);
        xhr.onload = function() {
          if (xhr.status === 200) {
            try {
              var data = JSON.parse(xhr.responseText);
              if (data.feed.entry) {
                allEntries = allEntries.concat(data.feed.entry);
                var total = parseInt(data.feed.openSearch$totalResults.$t, 10);
                if (allEntries.length < total) {
                  fetchPage(allEntries.length + 1);
                  return;
                }
              }
            } catch(e) {}
          }
          callback(allEntries);
        };
        xhr.onerror = function() { callback(allEntries); };
        xhr.send();
      }
      fetchPage(1);
    }

    // === Get post URL from entry ===
    function getEntryUrl(entry) {
      var links = entry.link || [];
      for (var i = 0; i < links.length; i++) {
        if (links[i].rel === 'alternate') return links[i].href;
      }
      return '#';
    }

    // === Check if entry has a specific label ===
    function entryHasLabel(entry, label) {
      var cats = entry.category || [];
      for (var i = 0; i < cats.length; i++) {
        if (cats[i].term === label) return true;
      }
      return false;
    }

    function escapeHtml(value) {
      return String(value == null ? '' : value).replace(/[&<>"']/g, function(ch) {
        return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[ch];
      });
    }

    function safeUrl(value) {
      var url = String(value || '#').trim();
      if (/^javascript:/i.test(url)) return '#';
      return url;
    }

    // === Reader tools: saved comfort settings and reading position ===
    var readerDefaults = { fontSize: 17, lineHeight: 2, width: 780 };

    function readJson(key, fallback) {
      try {
        var value = localStorage.getItem(key);
        return value ? JSON.parse(value) : fallback;
      } catch (e) {
        return fallback;
      }
    }

    function writeJson(key, value) {
      try {
        localStorage.setItem(key, JSON.stringify(value));
      } catch (e) {}
    }

    function getReaderSettings() {
      var settings = readJson('arwn-reader-settings', readerDefaults);
      settings.fontSize = Math.min(24, Math.max(14, parseInt(settings.fontSize, 10) || readerDefaults.fontSize));
      settings.lineHeight = Math.min(2.6, Math.max(1.6, parseFloat(settings.lineHeight) || readerDefaults.lineHeight));
      settings.width = Math.min(980, Math.max(620, parseInt(settings.width, 10) || readerDefaults.width));
      return settings;
    }

    function applyReaderSettings(settings) {
      document.documentElement.style.setProperty('--arwn-reader-font-size', settings.fontSize + 'px');
      document.documentElement.style.setProperty('--arwn-reader-line-height', settings.lineHeight);
      document.documentElement.style.setProperty('--arwn-reader-width', settings.width + 'px');
      writeJson('arwn-reader-settings', settings);
    }

    function getReadingMinutes(postBody) {
      var text = (postBody.textContent || '').trim();
      if (!text) return 1;
      var words = text.split(/\s+/).length;
      return Math.max(1, Math.ceil(words / 220));
    }

    function addReaderTools(postBody, currentUrl, isChapter) {
      var settings = getReaderSettings();
      applyReaderSettings(settings);

      var tools = document.createElement('div');
      tools.className = 'arwn-reader-tools';

      var meta = document.createElement('div');
      meta.className = 'arwn-reader-meta';
      meta.textContent = 'وقت القراءة التقريبي: ' + getReadingMinutes(postBody) + ' دقيقة';

      var controls = document.createElement('div');
      controls.className = 'arwn-reader-controls';

      function addButton(label, title, handler) {
        var button = document.createElement('button');
        button.type = 'button';
        button.textContent = label;
        button.title = title;
        button.setAttribute('aria-label', title);
        button.addEventListener('click', handler);
        controls.appendChild(button);
      }

      addButton('A-', 'تصغير الخط', function() {
        settings.fontSize = Math.max(14, settings.fontSize - 1);
        applyReaderSettings(settings);
      });
      addButton('A+', 'تكبير الخط', function() {
        settings.fontSize = Math.min(24, settings.fontSize + 1);
        applyReaderSettings(settings);
      });
      addButton('تباعد-', 'تقليل تباعد الأسطر', function() {
        settings.lineHeight = Math.max(1.6, Math.round((settings.lineHeight - 0.1) * 10) / 10);
        applyReaderSettings(settings);
      });
      addButton('تباعد+', 'زيادة تباعد الأسطر', function() {
        settings.lineHeight = Math.min(2.6, Math.round((settings.lineHeight + 0.1) * 10) / 10);
        applyReaderSettings(settings);
      });
      addButton('عرض', 'تبديل عرض النص', function() {
        settings.width = settings.width >= 900 ? 720 : settings.width + 90;
        applyReaderSettings(settings);
      });
      addButton('إعادة', 'استعادة إعدادات القراءة', function() {
        settings = { fontSize: readerDefaults.fontSize, lineHeight: readerDefaults.lineHeight, width: readerDefaults.width };
        applyReaderSettings(settings);
      });

      tools.appendChild(meta);
      tools.appendChild(controls);
      postBody.parentNode.insertBefore(tools, postBody);

      var backTop = document.createElement('button');
      backTop.type = 'button';
      backTop.className = 'arwn-back-top';
      backTop.textContent = '↑';
      backTop.title = 'العودة للأعلى';
      backTop.setAttribute('aria-label', 'العودة للأعلى');
      backTop.addEventListener('click', function() {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      });
      document.body.appendChild(backTop);

      var titleEl = document.querySelector('.post-title');
      var title = titleEl ? titleEl.textContent.trim() : document.title;
      var saveTimer = null;

      function updateReadingState() {
        var scrollTop = window.pageYOffset || document.documentElement.scrollTop;
        var docHeight = Math.max(1, document.documentElement.scrollHeight - document.documentElement.clientHeight);
        var progress = Math.min(100, Math.max(0, Math.round((scrollTop / docHeight) * 100)));
        backTop.classList.toggle('is-visible', scrollTop > 500);

        if (isChapter || progress > 8) {
          writeJson('arwn-last-read', {
            title: title,
            url: currentUrl,
            scrollTop: scrollTop,
            progress: progress,
            updatedAt: Date.now()
          });
        }
      }

      window.addEventListener('scroll', function() {
        if (saveTimer) return;
        saveTimer = setTimeout(function() {
          saveTimer = null;
          updateReadingState();
        }, 250);
      });
      updateReadingState();

      var resumeState = readJson('arwn-last-read', null);
      if (window.location.hash === '#arwn-resume' && resumeState && resumeState.url === currentUrl && resumeState.scrollTop) {
        setTimeout(function() {
          window.scrollTo({ top: resumeState.scrollTop, behavior: 'smooth' });
        }, 350);
      }
    }

    function addContinueReadingCard() {
      var lastRead = readJson('arwn-last-read', null);
      if (!lastRead || !lastRead.url || !lastRead.title) return;

      var host = document.getElementById('arwn-latest-updates') || document.getElementById('arwn-home-libraries');
      if (!host || document.getElementById('arwn-continue-reading')) return;

      var card = document.createElement('div');
      card.id = 'arwn-continue-reading';
      card.className = 'arwn-continue-card is-visible';

      var info = document.createElement('div');
      var title = document.createElement('span');
      title.className = 'arwn-continue-title';
      title.textContent = 'تابع القراءة: ' + lastRead.title;
      var progress = document.createElement('span');
      progress.className = 'arwn-continue-progress';
      progress.textContent = 'وصلت إلى ' + (lastRead.progress || 0) + '% من الصفحة';
      info.appendChild(title);
      info.appendChild(progress);

      var link = document.createElement('a');
      link.className = 'arwn-continue-link';
      link.href = lastRead.url + '#arwn-resume';
      link.textContent = 'متابعة';

      card.appendChild(info);
      card.appendChild(link);
      host.parentNode.insertBefore(card, host);
    }

    // =============================================
    // NOVEL INDEX: Auto-load chapter list
    // =============================================
    if (isSinglePost()) {
      var labels = getPostLabels();
      var novelLabel = getNovelLabel(labels);
      var isChapter = labels.indexOf('فصل') !== -1;
      var isNovelIndex = novelLabel && !isChapter;
      var currentUrl = window.location.href.split('?')[0].split('#')[0];
      var activePostBody = document.querySelector('.post-body');

      if (activePostBody && isChapter) {
        addReaderTools(activePostBody, currentUrl, isChapter);
      }

      if (isNovelIndex && novelLabel) {
        // This is a novel index page - show chapter list
        var postBody = activePostBody;
        if (postBody) {
          var indexDiv = document.createElement('div');
          indexDiv.id = 'arwn-chapter-index';
          indexDiv.innerHTML = '<h3>فهرس الفصول</h3><div class="arwn-chapter-loading">جاري تحميل الفصول...</div>';
          postBody.appendChild(indexDiv);

          fetchAllByLabel(novelLabel, function(entries) {
            // Filter to chapters only
            var chapters = entries.filter(function(e) {
              return entryHasLabel(e, 'فصل');
            });

            // Sort by publish date (oldest first)
            chapters.sort(function(a, b) {
              return new Date(a.published.$t) - new Date(b.published.$t);
            });

            var indexContent = indexDiv;
            if (chapters.length === 0) {
              indexContent.innerHTML = '<h3>فهرس الفصول</h3><p style="color:var(--text-secondary);text-align:center;padding:20px;">لم تُنشر أي فصول بعد.</p>';
              return;
            }

            var html = '<h3>فهرس الفصول <span style="font-size:14px;color:var(--text-secondary);font-weight:400;">(' + chapters.length + ' فصل)</span></h3>';
            html += '<ul class="arwn-chapter-list">';
            chapters.forEach(function(ch, i) {
              var url = escapeHtml(safeUrl(getEntryUrl(ch)));
              var title = escapeHtml(ch.title.$t);
              var date = escapeHtml(formatDate(ch.published.$t));
              html += '<li class="arwn-chapter-item">';
              html += '<span style="color:var(--accent-gold);font-weight:700;min-width:30px;">' + (i+1) + '</span>';
              html += '<a href="' + url + '">' + title + '</a>';
              html += '<span class="arwn-chapter-date">' + date + '</span>';
              html += '</li>';
            });
            html += '</ul>';
            indexContent.innerHTML = html;

            // === Auto-update chapter count in novel info ===
            var chCountEl = document.querySelector('.arwn-chapter-count');
            if (chCountEl) {
              chCountEl.textContent = chapters.length + ' فصل';
            }
          });

          // === Auto-add badges based on labels ===
          var badgesContainer = document.querySelector('.arwn-novel-badges');
          if (badgesContainer) {
            if (labels.indexOf('ويب-نوفل') !== -1) {
              badgesContainer.innerHTML += '<span class="arwn-badge arwn-badge-webnovel">⚔️ ويب نوفل</span>';
            }
            if (labels.indexOf('لايت-نوفل') !== -1) {
              badgesContainer.innerHTML += '<span class="arwn-badge arwn-badge-lightnovel">📚 لايت نوفل</span>';
            }
            if (labels.indexOf('مكتملة') !== -1) {
              badgesContainer.innerHTML += '<span class="arwn-badge arwn-badge-completed">🔵 مكتملة</span>';
            } else if (labels.indexOf('مستمرة') !== -1) {
              badgesContainer.innerHTML += '<span class="arwn-badge arwn-badge-ongoing">🟢 مستمرة</span>';
            }
          }
        }
      }

      // =============================================
      // CHAPTER PAGE: Add prev/next navigation
      // =============================================
      if (isChapter && novelLabel) {
        fetchAllByLabel(novelLabel, function(entries) {
          // Get all chapters sorted by date
          var chapters = entries.filter(function(e) {
            return entryHasLabel(e, 'فصل');
          });
          chapters.sort(function(a, b) {
            return new Date(a.published.$t) - new Date(b.published.$t);
          });

          // Find novel index page URL
          var novelIndexUrl = '#';
          for (var n = 0; n < entries.length; n++) {
            if (!entryHasLabel(entries[n], 'فصل')) {
              novelIndexUrl = getEntryUrl(entries[n]);
              break;
            }
          }

          // Find current chapter position
          var currentIndex = -1;
          for (var c = 0; c < chapters.length; c++) {
            var chUrl = getEntryUrl(chapters[c]).split('?')[0].split('#')[0];
            if (chUrl === currentUrl) {
              currentIndex = c;
              break;
            }
          }

          if (currentIndex === -1) return;

          var prevUrl = currentIndex > 0 ? getEntryUrl(chapters[currentIndex - 1]) : null;
          var nextUrl = currentIndex < chapters.length - 1 ? getEntryUrl(chapters[currentIndex + 1]) : null;

          // Build navigation bar
          var navHtml = '<div class="arwn-chapter-nav">';
          navHtml += prevUrl
            ? '<a class="arwn-nav-next" href="' + prevUrl + '">→ الفصل السابق</a>'
            : '<a class="arwn-nav-next arwn-nav-disabled">→ الفصل السابق</a>';
          navHtml += '<a class="arwn-nav-index" href="' + novelIndexUrl + '">📖 الفهرس</a>';
          navHtml += nextUrl
            ? '<a class="arwn-nav-prev" href="' + nextUrl + '">الفصل التالي ←</a>'
            : '<a class="arwn-nav-prev arwn-nav-disabled">الفصل التالي ←</a>';
          navHtml += '</div>';

          var postBody = document.querySelector('.post-body');
          if (postBody) {
            // Add nav before and after post body
            postBody.insertAdjacentHTML('beforebegin', navHtml);
            postBody.insertAdjacentHTML('afterend', navHtml);
          }

          // === Reading Progress Bar ===
          var progressBar = document.createElement('div');
          progressBar.id = 'arwn-reading-progress';
          document.body.appendChild(progressBar);

          window.addEventListener('scroll', function() {
            var scrollTop = window.pageYOffset || document.documentElement.scrollTop;
            var docHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
            var progress = (scrollTop / docHeight) * 100;
            progressBar.style.width = Math.min(progress, 100) + '%';
          });
        });
      }
    }

    // =============================================
    // PHASE 4: Card visual differentiation
    // =============================================
    if (!isSinglePost()) {
      var postContainers = document.querySelectorAll('.post-outer-container');
      postContainers.forEach(function(container) {
        var labelLinks = container.querySelectorAll('.byline.post-labels a');
        var postLabels = [];
        for (var i = 0; i < labelLinks.length; i++) {
          postLabels.push(labelLinks[i].textContent.trim());
        }

        var titleEl = container.querySelector('.post-title');
        if (!titleEl) return;

        var isWebNovel = postLabels.indexOf('ويب-نوفل') !== -1;
        var isLightNovel = postLabels.indexOf('لايت-نوفل') !== -1;
        var isChapter = postLabels.indexOf('فصل') !== -1;
        var isOngoing = postLabels.indexOf('مستمرة') !== -1;
        var isCompleted = postLabels.indexOf('مكتملة') !== -1;

        // Add type CSS class to card
        if (isChapter) {
          container.classList.add('arwn-type-chapter');
        } else if (isWebNovel) {
          container.classList.add('arwn-type-webnovel');
        } else if (isLightNovel) {
          container.classList.add('arwn-type-lightnovel');
        }

        // Add type badge after title
        if (isWebNovel && !isChapter) {
          var badge = document.createElement('span');
          badge.className = 'arwn-post-badge';
          badge.textContent = '⚔️ ويب نوفل';
          titleEl.parentNode.insertBefore(badge, titleEl.nextSibling);
        } else if (isLightNovel) {
          var badge2 = document.createElement('span');
          badge2.className = 'arwn-post-badge';
          badge2.textContent = '📚 لايت نوفل';
          titleEl.parentNode.insertBefore(badge2, titleEl.nextSibling);
        } else if (isChapter) {
          // Find novel name from labels
          var novelName = '';
          for (var nl = 0; nl < postLabels.length; nl++) {
            if (postLabels[nl].indexOf('رواية-') === 0) {
              novelName = postLabels[nl].replace('رواية-', '');
              break;
            }
          }
          if (novelName) {
            var chBadge = document.createElement('span');
            chBadge.className = 'arwn-post-badge';
            chBadge.style.background = 'var(--label-bg)';
            chBadge.style.color = 'var(--accent-light)';
            chBadge.textContent = '📖 ' + novelName;
            titleEl.parentNode.insertBefore(chBadge, titleEl.nextSibling);
          }
        }

        // Add status meta
        if ((isWebNovel || isLightNovel) && !isChapter) {
          var metaDiv = document.createElement('div');
          metaDiv.className = 'arwn-post-meta';
          if (isOngoing) {
            metaDiv.innerHTML = '<span class="arwn-post-status ongoing">🟢 مستمرة</span>';
          } else if (isCompleted) {
            metaDiv.innerHTML = '<span class="arwn-post-status completed">🔵 مكتملة</span>';
          }
          var postBottom = container.querySelector('.post-bottom');
          if (postBottom) {
            postBottom.parentNode.insertBefore(metaDiv, postBottom);
          }
        }
      });
    }

    // =============================================
    // PHASE 5: Homepage Dynamic Sections
    // =============================================
    if (!isSinglePost()) {
      addContinueReadingCard();

      // Reusable function to fetch JSON feed
      function fetchFeed(label, maxResults, callback) {
        var url = '/feeds/posts/default';
        if (label) {
          url += '/-/' + encodeURIComponent(label);
        }
        url += '?alt=json&max-results=' + maxResults;
        var script = document.createElement('script');
        var callbackName = 'arwn_cb_' + Math.round(Math.random() * 1000000);
        window[callbackName] = function(data) {
          var entries = data.feed.entry || [];
          callback(entries);
          delete window[callbackName];
          document.body.removeChild(script);
        };
        script.src = url + '&callback=' + callbackName;
        document.body.appendChild(script);
      }

      // Extract first image from HTML content
      function getFirstImage(content) {
        var m = content.match(/<img[^>]+src="([^">]+)"/);
        return m ? m[1] : '';
      }

      // Render Latest Updates
      var updatesContainer = document.getElementById('arwn-latest-updates');
      if (updatesContainer) {
        updatesContainer.innerHTML = '<h3 class="arwn-section-title">🔄 آخر التحديثات</h3><ul class="arwn-latest-list" id="arwn-latest-list"><li>جاري التحميل...</li></ul>';
        // Fetch latest 10 chapters
        fetchFeed('فصل', 10, function(entries) {
          var list = document.getElementById('arwn-latest-list');
          if (entries.length === 0) {
            list.innerHTML = '<li>لا توجد تحديثات.</li>';
            return;
          }
          var html = '';
          entries.forEach(function(entry) {
            var url = escapeHtml(safeUrl(getEntryUrl(entry)));
            var title = escapeHtml(entry.title.$t);
            var date = escapeHtml(formatDate(entry.published.$t));

            // Extract labels to find novel name if it's a chapter
            var isChapter = entryHasLabel(entry, 'فصل');
            var novelName = '';
            var novelBadgeHtml = '';

            if (entry.category) {
              for (var c = 0; c < entry.category.length; c++) {
                var term = entry.category[c].term;
                if (term.indexOf('رواية-') === 0) {
                  novelName = escapeHtml(term.replace('رواية-', ''));
                  break;
                }
              }
            }

            if (isChapter && novelName) {
              novelBadgeHtml = '<span class="arwn-post-badge" style="background:var(--label-bg);color:var(--accent-light);">📖 ' + novelName + '</span>';
            } else if (entryHasLabel(entry, 'ويب-نوفل')) {
              novelBadgeHtml = '<span class="arwn-post-badge">⚔️ ويب نوفل</span>';
            } else if (entryHasLabel(entry, 'لايت-نوفل')) {
              novelBadgeHtml = '<span class="arwn-post-badge">📚 لايت نوفل</span>';
            }

            html += '<li class="arwn-update-item">';
            html += '<div class="arwn-update-content">';
            if (novelBadgeHtml) html += novelBadgeHtml;
            html += '<a href="' + url + '" class="arwn-update-title">' + title + '</a>';
            html += '</div>';
            html += '<span class="arwn-update-date">' + date + '</span>';
            html += '</li>';
          });
          list.innerHTML = html;
        });
      }

      // Render Featured Carousel
      var carouselContainer = document.getElementById('arwn-featured-carousel');
      if (carouselContainer) {
        carouselContainer.innerHTML = '<h3 class="arwn-section-title">✨ الروايات المميزة</h3><div class="arwn-carousel-track" id="arwn-carousel-track">جاري التحميل...</div>';
        fetchFeed('مميزة', 8, function(entries) {
          var track = document.getElementById('arwn-carousel-track');
          if (entries.length === 0) {
            track.innerHTML = '<p style="color:var(--text-secondary);">لا توجد روايات مميزة حالياً.</p>';
            return;
          }
          var html = '';
          entries.forEach(function(entry) {
            var url = escapeHtml(safeUrl(getEntryUrl(entry)));
            var title = escapeHtml(entry.title.$t);
            var img = escapeHtml(safeUrl(getFirstImage(entry.content.$t)));
            html += '<div class="arwn-carousel-item"><a href="' + url + '">';
            if (img) {
              html += '<img class="arwn-carousel-cover" src="' + img + '" alt="' + title + '" loading="lazy" decoding="async"/>';
            } else {
              html += '<div class="arwn-carousel-cover" style="background:var(--border-color);display:flex;align-items:center;justify-content:center;">بدون غلاف</div>';
            }
            html += '<div class="arwn-carousel-info"><span class="arwn-carousel-title">' + title + '</span></div>';
            html += '</a></div>';
          });
          track.innerHTML = html;
        });
      }

      // Render Library Sections
      var libContainer = document.getElementById('arwn-home-libraries');
      if (libContainer) {
        // Web Novel Lib
        var wnLib = document.createElement('div');
        wnLib.id = 'arwn-lib-webnovel';
        wnLib.className = 'arwn-section';
        wnLib.innerHTML = '<h3 class="arwn-section-title">📖 مكتبة ويب نوفل</h3><div class="arwn-library-grid" id="arwn-grid-webnovel">جاري التحميل...</div>';
        libContainer.appendChild(wnLib);

        fetchFeed('ويب-نوفل', 8, function(entries) {
          var grid = document.getElementById('arwn-grid-webnovel');
          // Filter out chapters
          var novels = entries.filter(function(e) { return !entryHasLabel(e, 'فصل'); });
          if (novels.length === 0) {
            grid.innerHTML = '<p style="color:var(--text-secondary);">لا توجد روايات حالياً.</p>';
            return;
          }
          var html = '';
          novels.forEach(function(entry) {
            var url = escapeHtml(safeUrl(getEntryUrl(entry)));
            var title = escapeHtml(entry.title.$t);
            var img = escapeHtml(safeUrl(getFirstImage(entry.content.$t)));
            html += '<div class="arwn-carousel-item"><a href="' + url + '">';
            if (img) html += '<img class="arwn-carousel-cover" src="' + img + '" loading="lazy" decoding="async"/>';
            else html += '<div class="arwn-carousel-cover" style="background:var(--border-color);"></div>';
            html += '<div class="arwn-carousel-info"><span class="arwn-carousel-title">' + title + '</span></div>';
            html += '</a></div>';
          });
          grid.innerHTML = html;
        });

        // Light Novel Lib
        var lnLib = document.createElement('div');
        lnLib.id = 'arwn-lib-lightnovel';
        lnLib.className = 'arwn-section';
        lnLib.innerHTML = '<h3 class="arwn-section-title">📚 مكتبة لايت نوفل</h3><div class="arwn-library-grid" id="arwn-grid-lightnovel">جاري التحميل...</div>';
        libContainer.appendChild(lnLib);

        fetchFeed('لايت-نوفل', 8, function(entries) {
          var grid = document.getElementById('arwn-grid-lightnovel');
          var novels = entries.filter(function(e) { return !entryHasLabel(e, 'فصل'); });
          if (novels.length === 0) {
            grid.innerHTML = '<p style="color:var(--text-secondary);">لا توجد روايات حالياً.</p>';
            return;
          }
          var html = '';
          novels.forEach(function(entry) {
            var url = escapeHtml(safeUrl(getEntryUrl(entry)));
            var title = escapeHtml(entry.title.$t);
            var img = escapeHtml(safeUrl(getFirstImage(entry.content.$t)));
            html += '<div class="arwn-carousel-item"><a href="' + url + '">';
            if (img) html += '<img class="arwn-carousel-cover" src="' + img + '" loading="lazy" decoding="async"/>';
            else html += '<div class="arwn-carousel-cover" style="background:var(--border-color);"></div>';
            html += '<div class="arwn-carousel-info"><span class="arwn-carousel-title">' + title + '</span></div>';
            html += '</a></div>';
          });
          grid.innerHTML = html;
        });
      }
    }

  }); // DOMContentLoaded
})();
//
